#!/data/data/com.termux/files/usr/bin/bash
[ -d /data/data/com.termux/files/usr/var/lib/proot-distro/installed-rootfs/void ] && proot-distro reset void || proot-distro install void

proot-distro login --isolated void -- /bin/bash -c '

# dns only allowed from 192.168.0.1
echo "bmFtZXNlcnZlciAxOTIuMTY4LjAuMQo=" | base64 -d > /etc/resolv.conf; 

# create bash/tmux settings
echo "IyEvYmluL2Jhc2gKc291cmNlIC5iYXNocmMK" | base64 -d > /root/.bash_profile; 

echo "" | base64 -d > /root/.bashrc

echo "" | base64 -d > /root/.tmux.conf

# new user
useradd k; 

# allow sudo without password
echo "IGsgQUxMPShBTEw6QUxMKSBOT1BBU1NXRDogQUxMCg==" | base64 -d >> /etc/sudoers; 

cp /root/.bash_profile /home/k/.bash_profile;
cp /root/.bashrc /home/k/.bashrc;
cp /root/.tmux.conf /home/k/.tmux.conf;

xbps-install -Suy xbps;
xbps-install -Suy;
xbps-install -Sy neovim curl zstd;
xbps-install -Sy bsdtar base-devel fontconfig-devel libX11-devel libXft-devel;
xbps-install -Sy lxde xfce4;

# remove policykit error
rm /etc/xdg/autostart/xfce-polkit.desktop

# setup font & compile st - suckless terminal
echo "" | base64 -d | bash

# st desktop entry
echo "" | base64 -d > /usr/share/applications/st.desktop
mkdir /home/k/Desktop
cp /usr/share/applications/st.desktop /home/k/Desktop/st.desktop

# install vscode
echo "Y3VybCAtZnNTTCAnaHR0cHM6Ly9jb2RlLnZpc3VhbHN0dWRpby5jb20vc2hhL2Rvd25sb2FkP2J1aWxkPXN0YWJsZSZvcz1saW51eC1hcm02NCcgLW8gL2hvbWUvay9WU0NvZGUudGFyLmd6CnRhciAteHBmIC9ob21lL2svVlNDb2RlLnRhci5neiAtQyAvaG9tZS9rLwo=" | base64 -d | bash

# vscode desktop entry
echo "" | base64 -d >> /usr/share/applications/code.desktop
cp /usr/share/applications/code.desktop /home/k/Desktop/code.desktop
'

#curl -fsSL https://ollama.com/install.sh | sh
#ollama serve
#ollama pull llama3.2:3b

echo "" | base64 -d > proot_void_startx.sh
chmod +x proot_void_startx.sh

./proot_void_startx.sh
